const item = $input.first();
const body = item.json.body ?? item.json;
const p    = body.payload ?? body;

const intentLabel = { high: '🔥 Горячий', medium: '🌡 Тёплый', low: '❄️ Холодный' };
const sourceLabel = { chat: '💬 Чат', manual: '👆 Кнопка', calculator: '🧮 Калькулятор' };

const budgetStr = (p.budgetMin || p.budgetMax)
  ? `${p.budgetMin ? (p.budgetMin / 1_000_000).toFixed(1) + ' млн' : '?'} — ${p.budgetMax ? (p.budgetMax / 1_000_000).toFixed(1) + ' млн' : '?'} ₽`
  : 'не указан';

const text = [
  `🆕 *Новый лид #${p.leadId}*`,
  ``,
  `👤 ${p.userName || 'Аноним'} ${p.userPhone ? `· ${p.userPhone}` : ''}`,
  `📧 ${p.userEmail || '—'}`,
  ``,
  `📊 Скор: *${p.score}/20*`,
  `${intentLabel[p.intent] || '❓ Неизвестно'}`,
  `💰 Бюджет: ${budgetStr}`,
  `📍 Источник: ${sourceLabel[p.source] || p.source}`,
  ``,
  p.snapshot?.viewedPropertiesCount
    ? `👁 Просмотрел ЖК: ${p.snapshot.viewedPropertiesCount}`
    : '',
].filter(Boolean).join('\n');

return [{ json: { text, leadId: p.leadId, score: p.score ?? 0 } }];
